import React, { useState } from 'react';

const App = () => {
  const [credits, setCredits] = useState(0);
  const handleIncrement = () => setCredits(credits + 1);
  const handleAddCredits = (event) => setCredits(parseInt(event.target.value) + credits);
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-lg">
        <h2 className="text-[#B7D7CD] font-bold">Credits Tracker</h2>
        <p className="text-white">Total Credits: {credits}</p>
      </div>
      <div className="bg-[#B7D7CD] p-4 rounded-lg mt-4">
        <button className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={handleIncrement}>Increment</button>
        <input className="bg-transparent border-b border-white w-full p-2 mt-4" type="number" onChange={handleAddCredits} placeholder="Add Credits"/>
      </div>
    </div>
  );
};

export default App;
